                const deptCostData = Object.keys(deptCosts).map(key => ({ departamento: key, custo: deptCosts[key] })).sort((a, b) => b.custo - a.custo); 
                
                const today = new Date(); const thirtyDaysFromNow = new Date(); thirtyDaysFromNow.setDate(today.getDate() + 30); 
